# Type definitions module - provides interfaces, enums used across the geometry library

interface IShape:
    @abstract
    def area(self) -> float:
        ...

    @abstract
    def perimeter(self) -> float:
        ...

interface IPrintable:
    @abstract
    def format(self) -> str:
        ...

enum ShapeType:
    Rectangle = 1
    Square = 2
    Circle = 3

